export const getChipStateClassName = (disabled = false, readonly = false, active = false, status) => {
    if (status && !disabled) {
        return `zen-chip--${status}`;
    }
    if (disabled) {
        return "zen-chip--disabled";
    }
    if (readonly) {
        return "zen-chip--readonly";
    }
    if (active) {
        return "zen-chip--active";
    }
    return "zen-chip--default";
};
export const getChipTriggerStateClassName = (disabled = false, isOpen = false, status) => {
    if (status && !disabled) {
        return `zen-chip--${status}`;
    }
    if (disabled) {
        return "zen-chip--disabled";
    }
    if (isOpen) {
        return "zen-chip--active";
    }
    return "zen-chip--default";
};
