import { formatDate } from "../../utils/formatDate";
export const parseLabel = (option, dateFormat, translate, toLocalFn) => {
    const localeFrom = toLocalFn(option.from);
    const localeTo = toLocalFn(option.to);
    if (localeFrom.getDate() === localeTo.getDate() &&
        localeFrom.getMonth() === localeTo.getMonth() &&
        localeFrom.getFullYear() === localeTo.getFullYear()) {
        return formatDate(localeFrom, dateFormat, translate);
    }
    return `${formatDate(localeFrom, dateFormat, translate)} - ${formatDate(localeTo, dateFormat, translate)}`;
};
