import { getAdvancedFilterString, prepareAdvancedOptions, prepareOptions, prepareSelectedOptions } from "./groupsFilterHelper";
import { compareFilters, getDefaultFilterState, getGroupDescription } from "./groupsHelper";
import { getAdvancedFilterNamedState, getCurrentlyDeselectedMenu, getCurrentlySelectedMenu, getGroupsTreeItem, getMenu, getPathToRoot, getSearchResultFromObject, getSelectedChildren } from "./stateReducer/stateReducerHelper";
export const getBackButtonName = (stateObj, currentId) => {
    if (!currentId) {
        return undefined;
    }
    const currentEl = getGroupsTreeItem(stateObj, currentId);
    return currentEl ? getGroupDescription(currentEl, stateObj.translate) : undefined;
};
export const isAllChildrenSelected = (stateObj, currentId) => {
    if (!currentId) {
        return false;
    }
    const selectedIds = new Set(stateObj.selectedIds);
    const currentEl = getGroupsTreeItem(stateObj, currentId);
    return currentEl && currentEl.children && currentEl.children.length ? currentEl.children.every(el => selectedIds.has(el.id)) : false;
};
const defaultGroupsMenu = { builtInGroups: [], userGroups: [], currentId: undefined };
export const createInitialOptions = (stateObj, limit, searchStr, value) => {
    let options;
    if (!searchStr) {
        options = getMenu(stateObj);
    }
    else {
        options = getSearchResultFromObject(stateObj, searchStr) || defaultGroupsMenu;
    }
    const preparedOptions = prepareOptions(stateObj.translate, value ? options[value].slice(0, limit) : [...options.builtInGroups.slice(0, limit / 2), ...options.userGroups.slice(0, limit / 2)], () => stateObj.selectedIds, (id) => getSelectedChildren(stateObj, id), false, (id) => getPathToRoot(stateObj, id));
    return preparedOptions;
};
export const createAdjustmentOptions = (stateObj, isWithColor, limit, currentId, value) => {
    let options;
    if (!currentId) {
        options = defaultGroupsMenu;
    }
    else {
        options = getMenu(stateObj, currentId);
    }
    const preparedOptions = prepareOptions(stateObj.translate, value ? options[value].slice(0, limit) : [...options.builtInGroups.slice(0, limit / 2), ...options.userGroups.slice(0, limit / 2)], () => stateObj.selectedIds, (id) => getSelectedChildren(stateObj, id), isWithColor, (id) => getPathToRoot(stateObj, id));
    return preparedOptions;
};
const getAdvancedFilterOptions = (state, newAdvancedOptions, additionalState) => {
    let advancedFilter;
    if (additionalState && !compareFilters(additionalState, getDefaultFilterState())) {
        advancedFilter = getAdvancedFilterNamedState(state, additionalState);
    }
    else {
        advancedFilter =
            newAdvancedOptions && !compareFilters(newAdvancedOptions, getDefaultFilterState())
                ? getAdvancedFilterNamedState(state, newAdvancedOptions)
                : undefined;
    }
    const advancedOptionsStrings = newAdvancedOptions
        ? getAdvancedFilterString(state.translate, getAdvancedFilterNamedState(state, state.advancedFilterState))
        : "";
    const currentOptionsString = advancedFilter ? getAdvancedFilterString(state.translate, advancedFilter) : "";
    return advancedFilter ? prepareAdvancedOptions([currentOptionsString], advancedOptionsStrings) : [];
};
export const createCurrentlySelectedOptions = (stateObj, value, isWithColor, additionalItems, limit, additionalState) => {
    const selectedItems = getCurrentlySelectedMenu(stateObj);
    const deselectedItems = additionalItems.length ? getCurrentlyDeselectedMenu(stateObj, additionalItems) : undefined;
    let preparedOptions;
    if (value === "advancedGroups") {
        preparedOptions = getAdvancedFilterOptions(stateObj, selectedItems.advancedGroups, additionalState);
    }
    else {
        const sortedItems = deselectedItems
            ? [...selectedItems[value], ...deselectedItems[value]].sort((val1, val2) => (val1.id > val2.id ? 1 : -1))
            : [...selectedItems[value]].sort((val1, val2) => (val1.id > val2.id ? 1 : -1));
        preparedOptions = prepareSelectedOptions(stateObj.translate, sortedItems.slice(0, limit), () => stateObj.selectedIds, isWithColor, (id) => getPathToRoot(stateObj, id));
    }
    return preparedOptions;
};
