import { useController, useForm } from "react-hook-form";
export const useFormField = (controller) => {
    // TODO: how to replace it?
    const { control: controlInner } = useForm();
    const { control, name, defaultValue, rules } = controller || {};
    const nameInner = name || "";
    const { field, fieldState } = useController({ name: nameInner, control: control || controlInner, defaultValue, rules });
    if (!control || !name) {
        return {
            field: null,
            fieldState: null
        };
    }
    return { field, fieldState };
};
